import logo from "./logo.svg";
import "./App.css";
import { useState } from "react";

const App = function () {
    return <Header />;
};

const Header = function () {
    return (
        <>
            <header className="header">
                <h1 className="header-app-name">Todoアプリ</h1>
                <select className="filter">
                    <option value="all" selected>
                        全て
                    </option>
                    <option value="yet">未着手</option>
                    <option value="in-progress">進行中</option>
                    <option value="done">完了</option>
                </select>
            </header>
        </>
    );
};
const Modal = function () {
    return (
        <div class="todo-modal hidden">
            <button type="button" class="todo-modal--close">
                &times;
            </button>
            <div class="input">
                <input type="text" class="input--main" placeholder="main" />
                <input type="text" class="input--sub" placeholder="sub" />
                <input type="date" class="input--start" placeholder="start" />
                <input type="date" class="input--deadline" placeholder="deadline" />
            </div>
            <button type="button" class="add-new-todo-btn">
                追加
            </button>
        </div>
    );
};
export default App;
